 	{
 		private const char Separator = ':';

 		/// <summary>
 		/// Formats session ID, stream ID, and sequence number into an event ID string.
 		/// </summary>
 		public static string Format(string sessionId, string streamId, long sequence)
 		{
 			string value = Convert.ToBase64String(Encoding.UTF8.GetBytes(sessionId));
 			string value2 = Convert.ToBase64String(Encoding.UTF8.GetBytes(streamId));
 			return $"{value}{58}{value2}{58}{sequence}";
 		}

 		/// <summary>
 		/// Attempts to parse an event ID into its component parts.
 		/// </summary>
 		public static bool TryParse(string eventId, out string sessionId, out string streamId, out long sequence)
 		{
 			sessionId = string.Empty;
 			streamId = string.Empty;
 			sequence = 0L;
 			ReadOnlySpan<char> source = eventId.AsSpan();
 			Span<Range> destination = stackalloc Range[4];
 			if (source.Split(destination, ':') != 3)
 			{
 				return false;
 			}
 			try
 			{
 				Range range = destination[0];
 				ReadOnlySpan<char> base64Chars = source[range.Start..range.End];
 				range = destination[1];
 				ReadOnlySpan<char> base64Chars2 = source[range.Start..range.End];
 				range = destination[2];
 				ReadOnlySpan<char> s = source[range.Start..range.End];
 				if (!TryDecodeBase64ToString(base64Chars, out sessionId) || !TryDecodeBase64ToString(base64Chars2, out streamId))
 				{
 					return false;
 				}
 				return long.TryParse(s, out sequence);
 			}
 			catch
 			{
 				return false;
 			}
 		}

 		private static bool TryDecodeBase64ToString(ReadOnlySpan<char> base64Chars, [NotNullWhen(true)] out string? result)
 		{
 			int length = base64Chars.Length;
 			Span<byte> span = ((length > 256) ? ((Span<byte>)new byte[length]) : stackalloc byte[length]);
 			Span<byte> span2 = span;
 			Encoding.UTF8.GetBytes(base64Chars, span2);
 			if (Base64.DecodeFromUtf8InPlace(span2, out var bytesWritten) != OperationStatus.Done)
 			{
 				result = null;
 				return false;
 			}
 			result = Encoding.UTF8.GetString(span2.Slice(0, bytesWritten));
 			return true;
 		}
 	}
